fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    val prefixXOR = LongArray(n + 1)
    prefixXOR[0] = 0L
    for (i in 1..n) {
        prefixXOR[i] = prefixXOR[i - 1] xor nums[i - 1]
    }

    val dp = LongArray(n + 1)
    dp[0] = 0L

    for (i in 1..n) {
        dp[i] = Long.MAX_VALUE
        for (j in 1..i - 1) {
            val currentMax = Math.max(dp[j], prefixXOR[i] xor prefixXOR[j])
            if (currentMax < dp[i]) {
                dp[i] = currentMax
            }
        }
    }

    return dp[n]
}
