function solve(nums, k) {
    const n = nums.length;
    const prefixXOR = new Array(n + 1);
    prefixXOR[0] = 0;
    for (let i = 1; i <= n; i++) {
        prefixXOR[i] = prefixXOR[i - 1] ^ nums[i - 1];
    }

    const dp = new Array(n + 1);
    dp[0] = 0;

    for (let i = 1; i <= n; i++) {
        dp[i] = Infinity;
        for (let j = 1; j < i; j++) {
            const currentMax = Math.max(dp[j], prefixXOR[i] ^ prefixXOR[j]);
            if (currentMax < dp[i]) {
                dp[i] = currentMax;
            }
        }
    }

    return dp[n];
}
